{"cells": [{"cell_type": "code", "source": "\nimport sqlite3\n\ndef add_pet():\n    conn = sqlite3.connect(\"withpaw.db\")\n    cursor = conn.cursor()\n    cursor.execute(\"SELECT id, name FROM user_profile\")\n    users = cursor.fetchall()\n    if not users:\n        print(\"No users found. Please create a user profile first.\")\n        conn.close()\n        return\n    print(\"User List:\")\n    for user in users:\n        print(f\"ID: {user[0]}, Name: {user[1]}\")\n    family_id = int(input(\"Enter family ID: \"))\n    name = input(\"Enter pet name: \")\n    age = int(input(\"Enter pet age: \"))\n    species = input(\"Enter pet species: \")\n    breed = input(\"Enter pet breed: \")\n    cursor.execute(\"INSERT INTO pets (name, age, species, breed, family_id) VALUES (?, ?, ?, ?, ?)\",\n                   (name, age, species, breed, family_id))\n    conn.commit()\n    conn.close()\n    print(f\"Pet {name} added successfully!\")\n\ndef update_pet():\n    conn = sqlite3.connect(\"withpaw.db\")\n    cursor = conn.cursor()\n    cursor.execute(\"SELECT id, name FROM pets\")\n    pets = cursor.fetchall()\n    if not pets:\n        print(\"No pets found. Please add a pet first.\")\n        conn.close()\n        return\n    print(\"Pet List:\")\n    for pet in pets:\n        print(f\"ID: {pet[0]}, Name: {pet[1]}\")\n    pet_id = int(input(\"Enter pet ID to update: \"))\n    name = input(\"New name (press Enter to keep current): \")\n    age = input(\"New age (press Enter to keep current): \")\n    updates = []\n    params = []\n    if name:\n        updates.append(\"name = ?\")\n        params.append(name)\n    if age:\n        updates.append(\"age = ?\")\n        params.append(int(age))\n    updates_query = \", \".join(updates)\n    query = f\"UPDATE pets SET {updates_query} WHERE id = ?\"\n    params.append(pet_id)\n    cursor.execute(query, tuple(params))\n    conn.commit()\n    conn.close()\n    print(\"Pet updated successfully!\")\n", "metadata": {}}], "metadata": {}, "nbformat": 4, "nbformat_minor": 5}